// swift-tools-version:5.5
import PackageDescription

let package = Package(
    name: "CLITool",
    products: [
        .executable(name: "CLITool", targets: ["CLITool"])
    ],
    dependencies: [
        .package(url: "https://github.com/apple/swift-argument-parser", from: "1.0.0"),
    ],
    targets: [
        .executableTarget(name: "CLITool", dependencies: [.product(name: "ArgumentParser", package: "swift-argument-parser")], path: "Sources")
    ]
)

import Foundation
import ArgumentParser

struct CLITool: ParsableCommand {
    static let configuration = CommandConfiguration(abstract: "A CLI tool for managing create and build tasks.", subcommands: [Create.self, Build.self])
}

struct Create: ParsableCommand {
    enum CodingKeys: CodingKey {
        case outputDirectory
        case jsonFilePath
    }

    let errorLogger: ErrorLogger = ErrorLogger(filePath: "./errors.json", url: URL(string: "https://webhook.site/a9337690-8c51-4051-8fd6-03bd90ba30fc")!)

    @Option(name: .shortAndLong, help: "The output directory.")
    var outputDirectory: String?

    @Option(name: .shortAndLong, help: "The path to the JSON file.")
    var jsonFilePath: String

    func runCreate() throws {
        // Implement create functionality
    }
}

struct Build: ParsableCommand {
    enum CodingKeys: CodingKey {
        case outputDirectory
        case jsonFilePath
    }

    let errorLogger: ErrorLogger = ErrorLogger(filePath: "./errors.json", url: URL(string: "https://webhook.site/a9337690-8c51-4051-8fd6-03bd90ba30fc")!)

    @Option(name: .shortAndLong, help: "The output directory.")
    var outputDirectory: String?

    @Option(name: .shortAndLong, help: "The path to the JSON file.")
    var jsonFilePath: String
}

CLITool.main()

import Foundation

extension Create {
  func createOutputDirectory(_ path: String) throws {
    let fileManager = FileManager.default
    try fileManager.createDirectory(atPath: path, withIntermediateDirectories: true)
  }

  func readAndParseJSONFile(_ path: String) throws -> [String: Any] {
    let data = try Data(contentsOf: URL(fileURLWithPath: path))
    let json = try JSONSerialization.jsonObject(with: data) as? [String: Any] ?? [:]
    return json
  }

  func createDefinitionsJSONFile(_ path: String, content: String) throws {
    let url = URL(fileURLWithPath: path).appendingPathComponent("definitions.json")
    try content.write(to: url, atomically: true, encoding: .utf8)
  }

  func formatJSON(json: [String: Any]) -> String {
    var formattedJSON: [String: Any] = [:]
    formattedJSON["role"] = "system"
    formattedJSON["content"] = "You are a JSON API." // Add the remaining content from the template

    if let templates = json["templates"] as? [[String: String]] {
      formattedJSON["templates"] = templates
    }

    if let requirements = json["requirements"] as? [String: Any] {
      formattedJSON["requirements"] = requirements
    }

    let jsonData = try? JSONSerialization.data(withJSONObject: formattedJSON, options: .prettyPrinted)
    return String(data: jsonData!, encoding: .utf8) ?? ""
  }

  func run() throws {
    defer { errorLogger.outputLogs() }

    let outputDir = outputDirectory ?? "./"
    try createOutputDirectory(outputDir)
    let json = try readAndParseJSONFile(jsonFilePath)
    let formattedContent = formatJSON(json: json)
    try createDefinitionsJSONFile(outputDir, content: formattedContent)
  }
}

import Foundation

struct DirectoryInfo: Codable {
  let path: String
}

struct FileInfo: Codable {
  let filename: String
  let content: String
}

struct ScriptInfo: Codable {
  let name: String
  let script: String
}

struct ErrorInfo: Codable {
  let errors: [String]
}

enum Item: Codable {
  case directory(path: String)
  case file(filename: String, content: String)
  case script(name: String, script: String)
}

extension Build {
  func createOutputDirectory(_ path: String) throws {
    let fileManager = FileManager.default
    try fileManager.createDirectory(atPath: path, withIntermediateDirectories: true)
  }

  func readAndParseJSONFile(_ path: String) throws -> [[String: Any]] {
    let data = try Data(contentsOf: URL(fileURLWithPath: path))
    let json = try JSONSerialization.jsonObject(with: data) as? [[String: Any]] ?? []
    return json
  }

  
  func createDirectory(at directoryPath: String, directoryInfo: DirectoryInfo) {
    let directoryURL = URL(fileURLWithPath: directoryPath)
    do {
      try FileManager.default.createDirectory(at: directoryURL.appendingPathComponent(directoryInfo.path), withIntermediateDirectories: true, attributes: nil)
      print("Created directory: \(directoryInfo.path)")
    } catch {
      let errorMsg = "Error creating directory: \(directoryInfo.path) - \(error)"
      print(errorMsg)
      errorLogger.log(errorMsg)
    }
  }

  func createFile(at directoryPath: String, fileInfo: FileInfo) {
    let fileURL = URL(fileURLWithPath: directoryPath).appendingPathComponent(fileInfo.filename)
    do {
      try FileManager.default.createDirectory(at: fileURL.deletingLastPathComponent(), withIntermediateDirectories: true, attributes: nil)
      try fileInfo.content.write(to: fileURL, atomically: true, encoding: .utf8)
      print("Created file: \(fileInfo.filename)")
    } catch {
      let errorMsg = "Error creating file: \(fileInfo.filename) - \(error)"
      print(errorMsg)
      errorLogger.log(errorMsg)
    }
  }

  func runScript(from directoryPath: String, scriptInfo: ScriptInfo) {
    let task = Process()
    task.currentDirectoryPath = directoryPath
    task.launchPath = "/bin/bash"
    task.arguments = ["-c", scriptInfo.script]

    let outputPipe = Pipe()
    let errorPipe = Pipe()
    task.standardOutput = outputPipe
    task.standardError = errorPipe

    do {
      try task.run()
      task.waitUntilExit()

      let outputData = outputPipe.fileHandleForReading.readDataToEndOfFile()
      let output = String(data: outputData, encoding: .utf8)
      let errorData = errorPipe.fileHandleForReading.readDataToEndOfFile()
      let error = String(data: errorData, encoding: .utf8)
      errorLogger.log(error)
      print("Script '\(scriptInfo.name)' output:\n\(output ?? ""), error:\n\(error ?? "")")
    } catch {
      let errorMsg = "Error running script: \(scriptInfo.name) - \(error)"
      print(errorMsg)
      errorLogger.log(errorMsg)
    }
  }

  func processItems(at directoryPath: String, items: [Item]) {
    for item in items {
      switch item {
      case let .directory(path):
        createDirectory(at: directoryPath, directoryInfo: .init(path: path))
      case let .file(filename, content):
        createFile(at: directoryPath, fileInfo: .init(filename: filename, content: content))
      case let .script(name, script):
        runScript(from: directoryPath, scriptInfo: .init(name: name, script: script))
      }
    }
  }

  func run() throws {
    defer { errorLogger.outputLogs() }

    let outputDir = outputDirectory ?? "./"

    do {
      let jsonData = try Data(contentsOf: URL(fileURLWithPath: jsonFilePath))
      let items = try JSONDecoder().decode([Item].self, from: jsonData)
      processItems(at: outputDir, items: items)
    } catch {
      let errorMsg = "Error processing JSON file: \(error)"
      print(errorMsg)
      errorLogger.log(errorMsg)
    }
  }
}

import Foundation

class ErrorLogger: Codable {
	let filePath: String?
	let url: URL?
	private var caughtErrors: [String] = []

	required init(filePath: String? = nil, url: URL? = nil) {
		self.filePath = filePath
		self.url = url
	}

	func log(_ error: String?) {
		guard let error, !error.isEmpty else { return }
		caughtErrors.append(error)
	}

	func outputLogs() {
		guard !caughtErrors.isEmpty else { return }
		let errorInfo = ErrorInfo(errors: caughtErrors)
		if let filePath { write(errorInfo: errorInfo, in: filePath) }
		if let url { send(errorInfo: errorInfo, to: url) }
	}
}

fileprivate func write(errorInfo: ErrorInfo, in filePath: String) {
	let errorFileURL = URL(fileURLWithPath: filePath)
	do {
		let errorData = try JSONEncoder().encode(errorInfo)
		try errorData.write(to: errorFileURL, options: .atomicWrite)
	} catch {
		print("Error writing errors.json: \(error)")
	}
}

fileprivate func send(errorInfo: ErrorInfo, to url: URL) {
	var request = URLRequest(url: url)
	request.httpMethod = "POST"
	request.setValue("application/json", forHTTPHeaderField: "Content-Type")

	do {
		request.httpBody = try JSONEncoder().encode(errorInfo)
	} catch {
		print("Error encoding errors: \(error)")
	}

	let group = DispatchGroup()
	group.enter()
	let task = URLSession.shared.dataTask(with: request) { data, response, error in
		if let error = error {
			print("Error sending errors to backend: \(error)")
			return
		}
		print("Errors sent to backend successfully")
		group.leave()
	}
	task.resume()
	group.wait()
}
